const frames = [
'',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'',
''
];

const totalFrames = frames.length;
const images = new Array(totalFrames);
let loadedCount = 0;
let currentFrame = 0;

const canvas = document.getElementById('scrollCanvas');
const ctx = canvas.getContext('2d');
const hero = document.getElementById('hero');
const progressBar = document.getElementById('progressBar');
const progressLabel = document.getElementById('progressLabel');
const frameCounter = document.getElementById('frameCounter');

function resizeCanvas(){
  canvas.width = window.innerWidth;
  canvas.height = window.innerHeight;
  if(images[currentFrame] && images[currentFrame].complete) drawFrame(currentFrame);
}

function drawFrame(i){
  const img = images[i];
  if(!img || !img.complete || !img.naturalWidth) return;
  ctx.clearRect(0,0,canvas.width,canvas.height);
  // Cover: maintain aspect ratio, fill canvas
  const scale = Math.max(canvas.width/img.naturalWidth, canvas.height/img.naturalHeight);
  const w = img.naturalWidth * scale;
  const h = img.naturalHeight * scale;
  // Shift image so face is centered-right on desktop like mobile view
  const xOffset = window.innerWidth > 900 ? (canvas.width - w) * 0.65 : (canvas.width - w) / 2;
  const x = xOffset;
  const y = (canvas.height - h)/2;
  ctx.drawImage(img, x, y, w, h);
}

// Preload
frames.forEach((src,i)=>{
  const img = new Image();
  img.onload = ()=>{
    loadedCount++;
    if(i===0) drawFrame(0);
  };
  img.src = 'data:image/png;base64,' + src;
  images[i] = img;
});

function onScroll(){
  const heroH = hero.offsetHeight - window.innerHeight;
  const scrolled = Math.max(0, window.scrollY);
  const progress = Math.min(1, scrolled / heroH);
  const frameIdx = Math.round(progress*(totalFrames-1));
  if(frameIdx !== currentFrame){
    currentFrame = frameIdx;
    drawFrame(currentFrame);
  }
  progressBar.style.setProperty('--p', (progress*100).toFixed(1)+'%');
  progressLabel.textContent = progress < 0.01 ? 'SCROLL' : Math.round(progress*100)+'%';
  frameCounter.textContent = String(frameIdx).padStart(2,'0') + ' / ' + String(totalFrames-1).padStart(2,'0');
}

window.addEventListener('scroll', onScroll, {passive:true});
window.addEventListener('resize', resizeCanvas);
resizeCanvas();

// Skill bar animations
const fills = document.querySelectorAll('.sg-fill');
const skillObs = new IntersectionObserver(entries=>{
  entries.forEach(e=>{
    if(e.isIntersecting){
      const fill = e.target;
      const w = parseFloat(fill.style.getPropertyValue('--w') || fill.getAttribute('style').match(/--w:([\.\d]+)/)[1]);
      fill.style.transform = `scaleX(${w})`;
      fill.classList.add('animated');
    }
  });
},{threshold:0.3});
fills.forEach(f=>skillObs.observe(f));

// Reveal animations
const revealEls = document.querySelectorAll('.reveal');
const revObs = new IntersectionObserver(entries=>{
  entries.forEach((e,i)=>{
    if(e.isIntersecting){
      setTimeout(()=>e.target.classList.add('in'), i*80);
      revObs.unobserve(e.target);
    }
  });
},{threshold:0.1});
revealEls.forEach(el=>revObs.observe(el));

// ======= ROADMAP SCROLL REVEAL =======
(function(){
  const rmSteps = document.querySelectorAll('.rm-step-scroll');
  const fillLine = document.getElementById('rmFillLine');
  const rmWrap = document.getElementById('roadmapWrap');

  function updateFillLine(){
    if(!fillLine || !rmWrap) return;
    const wrapTop = rmWrap.getBoundingClientRect().top + window.scrollY;
    const wrapH = rmWrap.offsetHeight;
    const scrolled = window.scrollY + window.innerHeight * 0.72;
    const pct = Math.min(100, Math.max(0, ((scrolled - wrapTop) / wrapH) * 100));
    fillLine.style.height = pct + '%';
  }

  const rmObs = new IntersectionObserver(entries=>{
    entries.forEach(entry=>{
      if(entry.isIntersecting){
        const el = entry.target;
        const idx = Array.from(rmSteps).indexOf(el);
        setTimeout(()=>{
          el.classList.add('rm-visible');
          el.classList.remove('rm-hidden');
        }, idx * 80);
        rmObs.unobserve(el);
      }
    });
  },{threshold:0.15, rootMargin:'0px 0px -50px 0px'});

  rmSteps.forEach(s => rmObs.observe(s));
  window.addEventListener('scroll', updateFillLine, {passive:true});
  updateFillLine();
})();

// Custom cursor
const cur = document.getElementById('cur');
const curRing = document.getElementById('curRing');
let mx=0,my=0,rx=0,ry=0;
document.addEventListener('mousemove',e=>{
  mx=e.clientX; my=e.clientY;
  cur.style.transform=`translate(${mx-5}px,${my-5}px)`;
});
(function animCursor(){
  rx+=(mx-rx)*.1; ry+=(my-ry)*.1;
  curRing.style.transform=`translate(${rx-20}px,${ry-20}px)`;
  requestAnimationFrame(animCursor);
})();